// Generated by Claude Opus 4.6

import { CoreV1Event } from '@kubernetes/client-node';
import { screen } from '@testing-library/react';
import React from 'react';
import { Provider } from 'react-redux';
import { Store } from 'redux';

import AgentPodEvents from '@/components/AgentPodEvents';
import getComponentRenderer from '@/services/__mocks__/getComponentRenderer';
import { MockStoreBuilder } from '@/store/__mocks__/mockStore';

jest.mock('@/components/WorkspaceEvents/Item');

const { renderComponent } = getComponentRenderer(getComponent);

describe('AgentPodEvents', () => {
  const podName = 'agent-pod-1';

  let event1: CoreV1Event;
  let event2: CoreV1Event;
  let eventNoMessage: CoreV1Event;
  let eventOtherPod: CoreV1Event;
  let eventNonPod: CoreV1Event;

  beforeEach(() => {
    event1 = {
      lastTimestamp: '2021-03-31T14:00:00Z' as unknown as Date,
      message: 'message 1',
      involvedObject: {
        kind: 'Pod',
        name: podName,
      },
      metadata: {
        uid: 'uid-1',
        resourceVersion: '1',
      },
    };
    event2 = {
      lastTimestamp: '2021-03-31T14:01:00Z' as unknown as Date,
      message: 'message 2',
      involvedObject: {
        kind: 'Pod',
        name: podName,
      },
      metadata: {
        uid: 'uid-2',
        resourceVersion: '2',
      },
    };
    eventNoMessage = {
      lastTimestamp: '2021-03-31T14:02:00Z' as unknown as Date,
      message: '',
      involvedObject: {
        kind: 'Pod',
        name: podName,
      },
      metadata: {
        uid: 'uid-3',
        resourceVersion: '3',
      },
    };
    eventOtherPod = {
      lastTimestamp: '2021-03-31T14:03:00Z' as unknown as Date,
      message: 'other pod message',
      involvedObject: {
        kind: 'Pod',
        name: 'other-pod',
      },
      metadata: {
        uid: 'uid-4',
        resourceVersion: '4',
      },
    };
    eventNonPod = {
      lastTimestamp: '2021-03-31T14:04:00Z' as unknown as Date,
      message: 'deployment message',
      involvedObject: {
        kind: 'Deployment',
        name: podName,
      },
      metadata: {
        uid: 'uid-5',
        resourceVersion: '5',
      },
    };
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render empty state when podName is undefined', () => {
    const store = new MockStoreBuilder().build();
    renderComponent(store, undefined);

    expect(screen.getByText('No events to show.')).toBeTruthy();
    expect(screen.getByText('Events will be streamed for a starting agent pod.')).toBeTruthy();
  });

  test('should render empty state when no events match the pod', () => {
    const store = new MockStoreBuilder().withEvents({ events: [eventOtherPod] }).build();
    renderComponent(store, podName);

    expect(screen.getByText('No events to show.')).toBeTruthy();
    expect(screen.getByText('Events will be streamed for the agent pod.')).toBeTruthy();
  });

  test('should render empty state when all pod events have no message', () => {
    const store = new MockStoreBuilder().withEvents({ events: [eventNoMessage] }).build();
    renderComponent(store, podName);

    expect(screen.getByText('No events to show.')).toBeTruthy();
  });

  test('should filter events by podName and kind Pod', () => {
    const store = new MockStoreBuilder()
      .withEvents({ events: [event1, eventOtherPod, eventNonPod] })
      .build();
    renderComponent(store, podName);

    const eventItems = screen.getAllByTestId('event-item');
    expect(eventItems.length).toBe(1);
  });

  test('should show correct number of events', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1, event2] }).build();
    renderComponent(store, podName);

    const eventItems = screen.getAllByTestId('event-item');
    expect(eventItems.length).toBe(2);
  });

  test('should filter out events without message', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1, eventNoMessage] }).build();
    renderComponent(store, podName);

    const eventItems = screen.getAllByTestId('event-item');
    expect(eventItems.length).toBe(1);
  });

  test('should display streaming status text', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1] }).build();
    renderComponent(store, podName);

    expect(screen.getByText('Streaming events...')).toBeTruthy();
    expect(screen.getByText('Older events are not stored.')).toBeTruthy();
  });

  test('should display event count using Pluralize', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1, event2] }).build();
    renderComponent(store, podName);

    expect(screen.getByText('2 events')).toBeTruthy();
  });

  test('should display singular event count', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1] }).build();
    renderComponent(store, podName);

    expect(screen.getByText('1 event')).toBeTruthy();
  });

  test('should apply className prop', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1] }).build();
    const { reRenderComponent } = renderComponent(store, podName, 'my-custom-class');
    expect(document.querySelector('.my-custom-class')).toBeTruthy();

    reRenderComponent(store, podName, 'another-class');
    expect(document.querySelector('.another-class')).toBeTruthy();
  });

  test('should sort events by time (newest first)', () => {
    const store = new MockStoreBuilder().withEvents({ events: [event1, event2] }).build();
    renderComponent(store, podName);

    const eventItems = screen.getAllByTestId('event-item');
    // event2 is newer, should appear first after sorting
    expect(eventItems.length).toBe(2);
  });

  test('should update when store events change', () => {
    const store1 = new MockStoreBuilder().withEvents({ events: [event1] }).build();
    const { reRenderComponent } = renderComponent(store1, podName);

    expect(screen.getAllByTestId('event-item').length).toBe(1);

    const store2 = new MockStoreBuilder().withEvents({ events: [event1, event2] }).build();
    reRenderComponent(store2, podName);

    expect(screen.getAllByTestId('event-item').length).toBe(2);
  });
});

function getComponent(
  store: Store,
  podName: string | undefined,
  className?: string,
): React.ReactElement {
  return (
    <Provider store={store}>
      <AgentPodEvents podName={podName} className={className} />
    </Provider>
  );
}
